private void xrTableCell52_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       // --- Declare values ---
decimal softShellEggs = 0;
decimal minorCrackedEggs = 0;
decimal majorCrackedEggs = 0;
decimal thinShellEggs = 0;
decimal otherEggs = 0;
decimal wholeEggs = 0;
decimal brokenEggs = 0;
decimal smallEggs = 0;
decimal overWeightEggs = 0;
decimal dirtyEggs = 0;
decimal deformityEggs = 0;
decimal crackedEggs = 0;
decimal doubleYolkEggs = 0;
decimal recEggs = 0;
decimal destroyedEggs = 0;
// --- Read values ---
if (GetCurrentColumnValue("SoftShellEggs") != null)
    softShellEggs = Convert.ToDecimal(GetCurrentColumnValue("SoftShellEggs"));

if (GetCurrentColumnValue("MinorCrackedEggs") != null)
    minorCrackedEggs = Convert.ToDecimal(GetCurrentColumnValue("MinorCrackedEggs"));

if (GetCurrentColumnValue("MajorCrackedEggs") != null)
    majorCrackedEggs = Convert.ToDecimal(GetCurrentColumnValue("MajorCrackedEggs"));

if (GetCurrentColumnValue("ThinShellEggs") != null)
    thinShellEggs = Convert.ToDecimal(GetCurrentColumnValue("ThinShellEggs"));

if (GetCurrentColumnValue("OtherEggs") != null)
    otherEggs = Convert.ToDecimal(GetCurrentColumnValue("OtherEggs"));

if (GetCurrentColumnValue("WholeEggs") != null)
    wholeEggs = Convert.ToDecimal(GetCurrentColumnValue("WholeEggs"));

if (GetCurrentColumnValue("RecEggs") != null)
    recEggs = Convert.ToDecimal(GetCurrentColumnValue("RecEggs"));

if (GetCurrentColumnValue("BrokenEggs") != null)
    brokenEggs = Convert.ToDecimal(GetCurrentColumnValue("BrokenEggs"));

if (GetCurrentColumnValue("SmallEggs") != null)
    smallEggs = Convert.ToDecimal(GetCurrentColumnValue("SmallEggs"));

if (GetCurrentColumnValue("OverWeightEggs") != null)
    overWeightEggs = Convert.ToDecimal(GetCurrentColumnValue("OverWeightEggs"));

if (GetCurrentColumnValue("DirtyEggs") != null)
    dirtyEggs = Convert.ToDecimal(GetCurrentColumnValue("DirtyEggs"));

if (GetCurrentColumnValue("DeformityEggs") != null)
    deformityEggs = Convert.ToDecimal(GetCurrentColumnValue("DeformityEggs"));

if (GetCurrentColumnValue("CrackedEggs") != null)
    crackedEggs = Convert.ToDecimal(GetCurrentColumnValue("CrackedEggs"));

if (GetCurrentColumnValue("DestroyedEggs") != null)
    destroyedEggs = Convert.ToDecimal(GetCurrentColumnValue("DestroyedEggs"));


if (GetCurrentColumnValue("DoubleYolkEggs") != null)
    doubleYolkEggs = Convert.ToDecimal(GetCurrentColumnValue("DoubleYolkEggs"));

// --- Sum them ---
decimal result =  softShellEggs + minorCrackedEggs + majorCrackedEggs + thinShellEggs +
                 otherEggs + wholeEggs + brokenEggs + smallEggs + overWeightEggs +
                 dirtyEggs + deformityEggs + crackedEggs + doubleYolkEggs + destroyedEggs  ;

// --- Add to group total ---
decimal percentage = 0;
if (recEggs != 0)
    percentage = (result * 100m) / recEggs;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = string.Format("{0:N0}\n{1:N2}", result , percentage);
TotalPerc += result;



}

