private void xrTableCell54_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        // --- Declare values ---
decimal hatchingEggs = 0;
decimal recEggs = 0;

// --- HatchingEggs ---
if (GetCurrentColumnValue("HatchingEggs") != null)
    hatchingEggs = Convert.ToDecimal(GetCurrentColumnValue("HatchingEggs"));

// --- RecEggs ---
if (GetCurrentColumnValue("RecEggs") != null)
    recEggs = Convert.ToDecimal(GetCurrentColumnValue("RecEggs"));

// --- Equation ---
decimal percentage = 0;
if (recEggs != 0)
    percentage = (hatchingEggs * 100m) / recEggs;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00"); // 2 decimals
TotalhatchingEggs  += hatchingEggs ;
TotalRecEggsHatch += recEggs ;


}

private void xrTableCell66_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    if(TotalRecEggsHatch != 0){
        TotalhatchingEggsReportPerc = (TotalhatchingEggs   * 100m) / TotalRecEggsHatch ;
        }
      xrTableCell66.Text = TotalhatchingEggsReportPerc.ToString("N2");

}

private void xrTableCell30_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       // --- Declare values ---
decimal smallEggs = 0;
decimal recEggs = 0;
decimal total = 0;
decimal totalPerc = 0;
decimal totalSpecialEggs = 0;
decimal TotalReport  = 0;
decimal TotalPercReport  = 0;
// --- Read values ---
if (GetCurrentColumnValue("SmallEggs") != null)
    smallEggs = Convert.ToDecimal(GetCurrentColumnValue("SmallEggs"));

if (GetCurrentColumnValue("RecEggs") != null)
    recEggs = Convert.ToDecimal(GetCurrentColumnValue("RecEggs"));

// --- Base total (SmallEggs) ---
total = smallEggs;

// --- IIf logic: SmallEggs % of RecEggs ---
if (recEggs != 0)
    totalPerc = (smallEggs * 100.0m / recEggs);

// --- Final sum ---
totalSpecialEggs = total + totalPerc ;


// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = string.Format("{0:N0}\n{1:N2}", smallEggs, totalPerc);
// --- Add to group totals ---
TotalReport += total;
TotalPercReport += totalPerc;
TotalSpecialEggsReport = TotalReport + TotalPercReport ;


}

